using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// UI de coleta de Runas de Apolo (Tarefa #11):
///
/// - Ao recolher uma Runa de Apolo (<see cref="PlayerProgress.RunasDeApoloChanged"/>),
///   mostra uma notificação pop-up com o contador actualizado (ex: "2 / 6
///   Runas de Apolo").
/// - Ao chegar a 6 (ou <see cref="runasRequired"/>), exibe a sequência
///   completa de desbloqueio do Emblema de Apolo:
///   1. Pop-up de progresso (fade-in) → mostra "6 / 6 Runas de Apolo".
///   2. Transição para o painel do Emblema de Apolo (emblema iluminado, texto
///      "EMBLEMA DE APOLO DESBLOQUEADO!").
///   3. Flash de Aura de Fogo: activa o <see cref="apoloAuraPreview"/> (VFX
///      filho do player) durante alguns segundos para dar um aperitivo.
///   4. Fade-out do painel.
///
/// <b>Montagem no Editor:</b>
/// - Canvas (Screen Space - Overlay) com "popupRoot" + "canvasGroup".
/// - <b>Popup (notificação por Runa):</b>
///   - "runaCountText": "N / 6 Runas de Apolo".
///   - "runaIconImage": ícone da Runa de Apolo (opcional).
/// - <b>Painel de Emblema (visível só no desbloqueio a 6):</b>
///   - "emblemPanelRoot": activado/desactivado pelo código — a notificação
///     e o painel de emblema podem ser o mesmo ou objectos separados dentro
///     do "popupRoot".
///   - "emblemImage": imagem do Emblema de Apolo.
///   - "emblemTitleText": "EMBLEMA DE APOLO DESBLOQUEADO!".
/// - <b>Aura de Fogo (preview):</b>
///   - "apoloAuraPreview": referência ao GameObject filho do player com o
///     efeito de Aura de Apolo (o mesmo que <see cref="PostGameAuraController"/>
///     activa permanentemente depois). Este script activa-o durante
///     "auraPreviewDuration" e depois desactiva-o (a activação permanente
///     fica a cargo do PostGameAuraController via EmblemManager.EmblemGranted).
/// </summary>
public class ApoloRunaCollectUI : MonoBehaviour
{
    public static ApoloRunaCollectUI Instance { get; private set; }

    // ── Configuração ──────────────────────────────────────────────────────────

    [Header("Configuração")]
    [Tooltip("Número de Runas de Apolo para o desbloqueio do Emblema. Deve coincidir com EmblemManager.runasDeApoloRequired.")]
    [Min(1)] public int runasRequired = 6;

    // ── UI — Pop-up de Progresso ──────────────────────────────────────────────

    [Header("Pop-up de Progresso (por Runa)")]
    [SerializeField] private GameObject popupRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private TMP_Text runaCountText;
    [SerializeField] private Image runaIconImage;
    [SerializeField] private Sprite runaIconSprite;

    // ── UI — Painel de Desbloqueio do Emblema ─────────────────────────────────

    [Header("Painel de Emblema (apenas ao atingir 6)")]
    [Tooltip("Root do painel de desbloqueio do Emblema de Apolo. Pode ser o mesmo que 'popupRoot' ou um sub-painel separado dentro do mesmo CanvasGroup.")]
    [SerializeField] private GameObject emblemPanelRoot;
    [SerializeField] private Image emblemImage;
    [Tooltip("EmblemData do Emblema de Apolo — usa .icon como sprite do emblema.")]
    [SerializeField] private EmblemData apoloEmblemData;
    [SerializeField] private TMP_Text emblemTitleText;
    [SerializeField] private string emblemTitleString = "EMBLEMA DE APOLO\nDESBLOQUEADO!";

    // ── Aura de Fogo (preview) ────────────────────────────────────────────────

    [Header("Aura de Fogo — Preview")]
    [Tooltip("GameObject filho do player com o VFX da Aura de Apolo. Activado temporariamente durante a animação de desbloqueio (preview). A activação permanente é gerida pelo PostGameAuraController.")]
    [SerializeField] private GameObject apoloAuraPreview;

    [Tooltip("Duração (segundos) do preview da Aura de Fogo durante a animação de desbloqueio.")]
    [Min(0.5f)] public float auraPreviewDuration = 3f;

    // ── Áudio ─────────────────────────────────────────────────────────────────

    [Header("Áudio")]
    [SerializeField] private AudioClip runaCollectSfx;
    [SerializeField] private AudioClip emblemUnlockFanfare;

    // ── Transição ─────────────────────────────────────────────────────────────

    [Header("Transição")]
    [SerializeField] private float fadeDuration = 0.25f;
    [Tooltip("Tempo com o pop-up de progresso (por Runa) visível, em segundos.")]
    [SerializeField] private float popupHoldDuration = 1.8f;
    [Tooltip("Tempo com o painel de Emblema visível (ao atingir 6), em segundos.")]
    [SerializeField] private float emblemHoldDuration = 4f;

    // ── Internos ──────────────────────────────────────────────────────────────

    private bool isAutoFallback;
    private bool isShowing;
    private readonly Queue<int> _queue = new Queue<int>(); // totais de Runas a mostrar

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
                Destroy(Instance.gameObject);
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null) canvasGroup.alpha = 0f;
        if (popupRoot != null) popupRoot.SetActive(false);
        if (emblemPanelRoot != null) emblemPanelRoot.SetActive(false);
        if (apoloAuraPreview != null) apoloAuraPreview.SetActive(false);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(ApoloRunaCollectUI) + " (Fallback)");
        var instance = go.AddComponent<ApoloRunaCollectUI>();
        instance.isAutoFallback = true;
    }

    private void OnEnable()
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.RunasDeApoloChanged += OnRunasDeApoloChanged;
    }

    private void OnDisable()
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.RunasDeApoloChanged -= OnRunasDeApoloChanged;
    }

    private void OnRunasDeApoloChanged(int total)
    {
        // Só mostra enquanto o total ainda não passou do máximo (não queremos
        // re-mostrar em saves já com o emblema obtido ao carregar).
        if (total < 1 || total > runasRequired) return;

        _queue.Enqueue(total);
        if (!isShowing) StartCoroutine(ShowQueueRoutine());
    }

    private IEnumerator ShowQueueRoutine()
    {
        isShowing = true;

        while (_queue.Count > 0)
        {
            int total = _queue.Dequeue();
            bool isUnlock = total >= runasRequired;

            AudioManager.Instance?.PlaySE(isUnlock ? emblemUnlockFanfare : runaCollectSfx);

            // Configurar pop-up de progresso.
            if (runaCountText != null)
                runaCountText.text = $"{Mathf.Min(total, runasRequired)} / {runasRequired} Runas de Apolo";

            if (runaIconImage != null)
            {
                runaIconImage.sprite = runaIconSprite;
                runaIconImage.gameObject.SetActive(runaIconSprite != null);
            }

            if (emblemPanelRoot != null) emblemPanelRoot.SetActive(false);

            // Mostra pop-up normal.
            if (canvasGroup == null)
            {
                yield return WaitUnscaled(popupHoldDuration);
            }
            else
            {
                if (popupRoot != null) popupRoot.SetActive(true);
                yield return FadeRoutine(0f, 1f);
                yield return WaitUnscaled(popupHoldDuration);

                if (!isUnlock)
                {
                    yield return FadeRoutine(1f, 0f);
                    if (popupRoot != null) popupRoot.SetActive(false);
                }
                else
                {
                    // Transição para o painel do Emblema.
                    yield return ShowEmblemUnlock();
                }
            }
        }

        isShowing = false;
    }

    private IEnumerator ShowEmblemUnlock()
    {
        // Mostra o painel do Emblema (fade cruzado ou substituição directa).
        if (emblemPanelRoot != null)
        {
            emblemPanelRoot.SetActive(true);

            if (emblemImage != null && apoloEmblemData != null)
                emblemImage.sprite = apoloEmblemData.icon;

            if (emblemTitleText != null)
                emblemTitleText.text = emblemTitleString;
        }

        // Preview da Aura de Fogo.
        if (apoloAuraPreview != null)
            apoloAuraPreview.SetActive(true);

        yield return WaitUnscaled(emblemHoldDuration);

        // Desactiva preview da aura (PostGameAuraController assume a seguir).
        if (apoloAuraPreview != null)
            apoloAuraPreview.SetActive(false);

        yield return FadeRoutine(1f, 0f);

        if (popupRoot != null) popupRoot.SetActive(false);
        if (emblemPanelRoot != null) emblemPanelRoot.SetActive(false);
    }

    // ── Utilitários ───────────────────────────────────────────────────────────

    private IEnumerator WaitUnscaled(float duration)
    {
        float t = 0f;
        while (t < duration) { t += Time.unscaledDeltaTime; yield return null; }
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;
        canvasGroup.alpha = from;
        if (fadeDuration <= 0f) { canvasGroup.alpha = to; yield break; }

        float t = 0f;
        while (t < fadeDuration)
        {
            t += Time.unscaledDeltaTime;
            canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        canvasGroup.alpha = to;
    }
}
